#include <vector>
#include <algorithm>
#include <numeric>
#include <cmath>

using namespace std;

long long solve(vector<long long> nums, long long maxC) {
    // Helper function to compute GCD
    auto gcd = [](long long a, long long b) {
        while (b) {
            long long temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    };

    // Find the longest stable subarray
    long long max_len = 0;
    for (int i = 0; i < nums.size(); ++i) {
        long long current_gcd = nums[i];
        if (current_gcd < 2) {
            continue;
        }
        for (int j = i; j < nums.size(); ++j) {
            current_gcd = gcd(current_gcd, nums[j]);
            if (current_gcd >= 2) {
                max_len = max(max_len, static_cast<long long>(j - i + 1));
            } else {
                break;
            }
        }
    }

    if (max_len == 0) {
        return 0;
    }

    // If we can modify one element to break the longest stable subarray
    if (maxC >= 1) {
        return max_len - 1;
    } else {
        return max_len;
    }
}
